//! Codegen for m1-core. `cargo run -p xtask -- gen-kinds` regenerates
//! `m1-core/src/kind.rs` from the grammar's node-types.json.

use std::collections::BTreeMap;
use std::path::{Path, PathBuf};

/// Symbolic (non-identifier) token types mapped to enum variant names.
/// NOTE: `=` is `Assign` (not `Eq`) so it does not collide with the keyword
/// `eq` which becomes `Eq`. Adding a new operator to the grammar without an
/// entry here makes the generator panic — intentional, so the map stays complete.
const SYMBOL_MAP: &[(&str, &str)] = &[
    ("!", "Bang"), ("!=", "BangEq"), ("%", "Percent"), ("&", "Amp"),
    ("&&", "AmpAmp"), ("(", "LParen"), (")", "RParen"), ("*", "Star"),
    ("*=", "StarEq"), ("+", "Plus"), ("+=", "PlusEq"), (",", "Comma"),
    ("-", "Minus"), ("-=", "MinusEq"), (".", "Dot"), ("/", "Slash"),
    ("/=", "SlashEq"), (":", "Colon"), (";", "Semicolon"), ("<", "Lt"),
    ("<<", "LtLt"), ("<=", "LtEq"), ("=", "Assign"), ("==", "EqEq"),
    (">", "Gt"), (">=", "GtEq"), (">>", "GtGt"), ("?", "Question"),
    ("^", "Caret"), ("{", "LBrace"), ("|", "Pipe"), ("||", "PipePipe"),
    ("}", "RBrace"),
];

fn is_ident(s: &str) -> bool {
    let mut chars = s.chars();
    match chars.next() {
        Some(c) if c.is_ascii_alphabetic() || c == '_' => {}
        _ => return false,
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_')
}

fn pascal_case(s: &str) -> String {
    s.split('_')
        .filter(|seg| !seg.is_empty())
        .map(|seg| {
            let mut c = seg.chars();
            let first = c.next().unwrap().to_ascii_uppercase();
            format!("{first}{}", c.as_str())
        })
        .collect()
}

fn variant_name(ty: &str) -> String {
    let name = if is_ident(ty) {
        pascal_case(ty)
    } else {
        SYMBOL_MAP
            .iter()
            .find(|(sym, _)| *sym == ty)
            .map(|(_, name)| name.to_string())
            .unwrap_or_else(|| panic!("no SYMBOL_MAP entry for token {ty:?}; add one in xtask"))
    };
    assert!(!name.is_empty(), "empty variant name generated for node type {ty:?}");
    name
}

/// Produce the full contents of `src/kind.rs` from a node-types.json string.
pub fn generate_kind_rs(node_types_json: &str) -> String {
    let parsed: serde_json::Value =
        serde_json::from_str(node_types_json).expect("node-types.json must be valid JSON");
    let entries = parsed.as_array().expect("node-types.json must be an array");

    // Distinct node type strings, sorted for deterministic output.
    let mut types: BTreeMap<String, ()> = BTreeMap::new();
    for e in entries {
        if let Some(t) = e.get("type").and_then(|v| v.as_str()) {
            types.insert(t.to_string(), ());
        }
    }

    // (variant_name, type_string), sorted by variant name; detect collisions.
    let mut variants: Vec<(String, String)> = types
        .keys()
        .map(|ty| (variant_name(ty), ty.clone()))
        .collect();
    variants.sort();
    for pair in variants.windows(2) {
        assert!(
            pair[0].0 != pair[1].0,
            "two node types map to variant {:?}: {:?} and {:?}",
            pair[0].0, pair[0].1, pair[1].1
        );
    }

    let mut out = String::new();
    out.push_str("// @generated by `cargo run -p xtask -- gen-kinds`. Do not edit by hand.\n");
    out.push_str("//! Typed node kinds for the M1 grammar, generated from node-types.json.\n\n");
    out.push_str("#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]\n");
    out.push_str("pub enum Kind {\n");
    for (variant, _) in &variants {
        out.push_str(&format!("    {variant},\n"));
    }
    out.push_str("    /// A node type not known when this file was generated.\n");
    out.push_str("    Other,\n");
    out.push_str("}\n\n");
    out.push_str("impl Kind {\n");
    out.push_str("    /// Map a tree-sitter kind string to a [`Kind`].\n");
    out.push_str("    pub fn from_kind_str(s: &str) -> Kind {\n");
    out.push_str("        match s {\n");
    for (variant, ty) in &variants {
        out.push_str(&format!("            {ty:?} => Kind::{variant},\n"));
    }
    out.push_str("            _ => Kind::Other,\n");
    out.push_str("        }\n");
    out.push_str("    }\n");
    out.push_str("}\n");
    out
}

fn kind_rs_path() -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR")).join("../src/kind.rs")
}

/// Produce the full contents of `src/field.rs` from a node-types.json string.
/// Field names are always grammar identifiers (snake_case), so this reuses
/// `pascal_case` and needs no symbol map.
pub fn generate_field_rs(node_types_json: &str) -> String {
    let parsed: serde_json::Value =
        serde_json::from_str(node_types_json).expect("node-types.json must be valid JSON");
    let entries = parsed.as_array().expect("node-types.json must be an array");

    // Distinct field-name strings across all node types, sorted for determinism.
    let mut fields: BTreeMap<String, ()> = BTreeMap::new();
    for e in entries {
        if let Some(obj) = e.get("fields").and_then(|v| v.as_object()) {
            for name in obj.keys() {
                fields.insert(name.clone(), ());
            }
        }
    }

    // (variant_name, field_string), sorted by variant name; detect collisions.
    let mut variants: Vec<(String, String)> = fields
        .keys()
        .map(|name| (pascal_case(name), name.clone()))
        .collect();
    variants.sort();
    for pair in variants.windows(2) {
        assert!(
            pair[0].0 != pair[1].0,
            "two field names map to variant {:?}: {:?} and {:?}",
            pair[0].0, pair[0].1, pair[1].1
        );
    }

    let mut out = String::new();
    out.push_str("// @generated by `cargo run -p xtask -- gen-kinds`. Do not edit by hand.\n");
    out.push_str("//! Typed node fields for the M1 grammar, generated from node-types.json.\n\n");
    out.push_str("#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]\n");
    out.push_str("pub enum Field {\n");
    for (variant, _) in &variants {
        out.push_str(&format!("    {variant},\n"));
    }
    out.push_str("}\n\n");
    out.push_str("impl Field {\n");
    out.push_str("    /// The grammar field-name string, for tree-sitter lookups.\n");
    out.push_str("    pub fn as_str(self) -> &'static str {\n");
    out.push_str("        match self {\n");
    for (variant, name) in &variants {
        out.push_str(&format!("            Field::{variant} => {name:?},\n"));
    }
    out.push_str("        }\n");
    out.push_str("    }\n");
    out.push_str("}\n");
    out
}

fn field_rs_path() -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR")).join("../src/field.rs")
}

fn main() {
    let arg = std::env::args().nth(1);
    match arg.as_deref() {
        None | Some("gen-kinds") => {
            let kind = generate_kind_rs(tree_sitter_m1::NODE_TYPES_JSON);
            let kind_path = kind_rs_path();
            std::fs::write(&kind_path, kind).expect("write src/kind.rs");
            println!("wrote {}", kind_path.display());

            let field = generate_field_rs(tree_sitter_m1::NODE_TYPES_JSON);
            let field_path = field_rs_path();
            std::fs::write(&field_path, field).expect("write src/field.rs");
            println!("wrote {}", field_path.display());
        }
        Some(other) => {
            eprintln!("unknown command {other:?}; usage: cargo run -p xtask -- gen-kinds");
            std::process::exit(2);
        }
    }
}

#[cfg(test)]
mod tests {
    #[test]
    fn kind_rs_is_fresh() {
        let expected = super::generate_kind_rs(tree_sitter_m1::NODE_TYPES_JSON);
        let actual = std::fs::read_to_string(super::kind_rs_path())
            .expect("src/kind.rs must exist — run `cargo run -p xtask -- gen-kinds`");
        assert_eq!(
            actual, expected,
            "src/kind.rs is stale; run `cargo run -p xtask -- gen-kinds`"
        );
    }

    #[test]
    fn field_rs_is_fresh() {
        let expected = super::generate_field_rs(tree_sitter_m1::NODE_TYPES_JSON);
        let actual = std::fs::read_to_string(super::field_rs_path())
            .expect("src/field.rs must exist — run `cargo run -p xtask -- gen-kinds`");
        assert_eq!(
            actual, expected,
            "src/field.rs is stale; run `cargo run -p xtask -- gen-kinds`"
        );
    }
}
